            PropertyState names = entry.getNodeState().getProperty("propertyNames");
            if (names != null) {
                for (int i = 0; i < names.count(); i++) {
                    if (name.equals(names.getValue(Type.STRING, i))) {
                        return entry.getNodeState();
                    }
                }
            }
        }
    }
    return null;
