                        computeGenKill(n.getLastChild(), gen, kill, true);
            return;
        case Token.HOOK:
            computeGenKill(n.getFirstChild(), gen, kill, conditional);
                        computeGenKill(n.getFirstChild().getNext(), gen, kill, true);
            computeGenKill(n.getLastChild(), gen, kill, true);
