boolean checkEquivalenceHelper(JSType that, boolean tolerateUnknowns) {
    if (this == that) {
        return true;
    }
    boolean thisUnknown = isUnknownType();
    boolean thatUnknown = that.isUnknownType();
    if (thisUnknown || thatUnknown) {
