    File file = new File(s);
    if (file.isAbsolute()) {
                s = file.getPath();
    } else if (file.getPath().startsWith(File.separator)) {
                s = file.getAbsolutePath();
    } else {
                s = new File(new File(basedir, s).toURI().normalize()).getAbsolutePath();
    }
    return s;
