                                                exp = exchange.getContext().getTypeConverter().convertTo(String.class, parameterValue);
                                if (!valid) {
                                        valid = parameterValue instanceof String || BeanHelper.isValidParameterValue(exp);
                }
                if (valid) {
                                        if (parameterValue instanceof String) {
