        if ((i % 2) == 0) {
            currentDigit *= 2;
            currentDigit = currentDigit > 9 ? currentDigit - 9 : currentDigit;
            sum += currentDigit;
        } else {
            sum += currentDigit;
        }
    }
    if (!((sum % 10) == 0)) {
        error(validatable);
    }
