                cssClass = " ";
            }
            cssClass += " tab" + getIndex();
            if (getIndex() == getSelectedTab()) {
                cssClass += ' ' + getSelectedTabCssClass();
            }
            if (getIndex() == getTabs().size() - 1) {
                cssClass += ' ' + getLastTabCssClass();
            }
