private static void escape(String s, int length, StringBuilder buff) {
    for (int i = 0; i < length; i++) {
        char c = s.charAt(i);
        int ic = (int) c;
        switch(c) {
            case '"':
                                buff.append("\\\"");
                break;
            case '\\':
                                buff.append("\\\\");
                break;
            case '\b':
                                buff.append("\\b");
                break;
            case '\f':
                                buff.append("\\f");
                break;
            case '\n':
                                buff.append("\\n");
                break;
            case '\r':
                                buff.append("\\r");
                break;
            case '\t':
                                buff.append("\\t");
                break;
            default:
                if (c < ' ') {
                    buff.append(String.format("\\u%04x", ic));
                } else if (ic >= 0xD800 && ic <= 0xDBFF) {
                                        if (i < length - 1 && Character.isSurrogatePair(c, s.charAt(i + 1))) {
                                                buff.append(c);
                        buff.append(s.charAt(i + 1));
                        i += 1;
                    } else {
                                                buff.append(String.format("\\u%04x", ic));
                    }
                } else {
                    buff.append(c);
                }
        }
    }
