                        } else if (parent.getType() == Token.LP) {
                        } else if (isVar) {
            Node grandparent = parent.getParent();
            Node value = n.hasChildren() ? v.getInitialValue().detachFromParent() : null;
            Node varNode = parent;
            String name = n.getString();
            int nameCount = scopedAliasNames.count(name);
