private static void escape(String s, int length, StringBuilder buff) {
    for (int i = 0; i < length; i++) {
        char c = s.charAt(i);
        switch(c) {
            case '"':
                                buff.append("\\\"");
                break;
            case '\\':
                                buff.append("\\\\");
                break;
            case '\b':
                                buff.append("\\b");
                break;
            case '\f':
                                buff.append("\\f");
                break;
            case '\n':
                                buff.append("\\n");
                break;
            case '\r':
                                buff.append("\\r");
                break;
            case '\t':
                                buff.append("\\t");
                break;
            default:
                if (c < ' ') {
                    buff.append("\\u00");
                                        buff.append(Character.forDigit(c >>> 4, 16));
                    buff.append(Character.forDigit(c & 15, 16));
                } else {
                    buff.append(c);
                }
        }
    }
