        }
    }
    if (!externalChanges.isEmpty()) {
                store.invalidateCache();
                docChildrenCache.invalidateAll();
                        backgroundOperationLock.writeLock().lock();
        try {
                                    revisionComparator.add(newRevision(), headSeen);
