        if (bufferOrEvent.isBuffer()) {
                        BufferProvider bufferProvider = inputChannel.getBufferProvider();
            if (bufferProvider == null) {
                                return false;
            }
            while (true) {
                Buffer buffer = bufferProvider.requestBuffer();
