        int len = idx + token.length() + 1;
        if (uri.length() >= len) {
            part = uri.substring(idx - 1, len);
        }
        if (StringHelper.isQuoted(part)) {
                                    pivot = idx + token.length() + 1;
            idx = uri.indexOf(token, pivot);
        } else {
                        return idx;
        }
    }
    return idx;
