                return -1;
            }
        }
    } else {
                while (i < delimLimit && !delimiterNext(bytes, i, delimiter)) {
            i++;
        }
        if (i >= delimLimit) {
                        reusable.setValueAscii(bytes, startPos, limit - startPos);
            return limit;
        } else {
                        reusable.setValueAscii(bytes, startPos, i - startPos);
            return i + delimiter.length;
        }
    }
