public P selectFarthest(final List<P> points, final EnclosingBall<S, P> ball) {
    final P center = ball.getCenter();
    P farthest = null;
    double dMax = -1.0;
    for (final P point : points) {
        final double d = point.distance(center);
        if (d > dMax) {
            farthest = point;
            dMax = d;
        }
    }
    return farthest;
