private boolean needsFullMapping(String path) {
    int length = path.length();
    if (length == 0) {
        return true;
    }
        int slash = -1;
        int colon = -1;
    switch(path.charAt(0)) {
                case '{':
                case '[':
                case '.':
        case         ':':
            return true;
        case '/':
            if (length == 1) {
                                return false;
            }
            slash = 0;
            break;
    }
    for (int i = 1; i < length; i++) {
        switch(path.charAt(i)) {
                        case '{':
            case             '[':
                return true;
            case '.':
                if (i == slash + 1) {
                                        return true;
                }
                break;
            case ':':
                if (                i == slash + 1 ||                 i == colon + i ||                 colon > slash || i + 1 == length) {
                                        return true;
                }
                colon = i;
                break;
            case '/':
                if (                i == slash + 1 ||                 i == colon + i || i + 1 == length) {
                                        return true;
                }
                slash = i;
                break;
        }
    }
    return colon != -1 && !nameMapper.getSessionLocalMappings().isEmpty();
