public static void escape(String s, int length, StringBuilder buff) {
        for (int i = 0; i < length; i++) {
        char c = s.charAt(i);
        switch(c) {
            case '"':
                                buff.append("\\\"");
                break;
            case '\\':
                                buff.append("\\\\");
                break;
            case '\b':
                                buff.append("\\b");
                break;
            case '\f':
                                buff.append("\\f");
                break;
            case '\n':
                                buff.append("\\n");
                break;
            case '\r':
                                buff.append("\\r");
                break;
            case '\t':
                                buff.append("\\t");
                break;
            default:
                if (c < ' ') {
                                        buff.append("\\u00");
                    String hex = Integer.toHexString(c);
                    if (hex.length() == 1) {
                        buff.append('0');
                    }
                    buff.append(hex);
                } else if (c >= 127) {
                                        buff.append("\\u");
                    String hex = Integer.toHexString(c);
                    for (int len = hex.length(); len < 4; len++) {
                        buff.append('0');
                    }
                    buff.append(hex);
                } else {
                    buff.append(c);
                }
        }
    }
